using OpenQA.Selenium;
using NipNetLib;
using System.IO;
using LexEna2BIG;


namespace WebClientJS   
{
    public class Utils
    {
        public static void LogWriter(string logMesgParam)
        {
            //Ustawienia ustawienia = new Ustawienia();
            //switch(ustawienia.logowanie)
            //{
            //   case 1:
            using (StreamWriter w = File.AppendText("NipValidatorLog.txt"))
            {
                Log(logMesgParam, w);

                // Close the writer and underlying file.
                w.Close();

            }

            //     break;
            //    case 2:
            //       System.Console.WriteLine(logMesgParam);
            //      break;

            //}

        }
        private static void Log(string logMessage, TextWriter w)
        {
            // w.Write("\r\nLog Entry : ");
            w.WriteLine("{0} {1}", DateTime.Now.ToLongTimeString(),
                DateTime.Now.ToLongDateString());
            // w.WriteLine("  :");
            w.WriteLine("{0}\t", logMessage);
            // w.WriteLine("-------------------------------");
            // Update the underlying file.
            w.Flush();
        }


    }


    class NipValidator
    {
        static void Main(string[] args)
        {
            /*         
            IWebDriver driver = new FirefoxDriver();// FirefoxDriver()
            driver.Manage().Timeouts().ImplicitWait = TimeSpan.FromSeconds(40);
            driver.Url= "https://ppuslugi.mf.gov.pl/?link=VAT&;";
            //#WebDriverWait wait = new WebDriverWait(driver, TimeSpan.FromSeconds(30));
            //#IWebElement myDynamicElement = wait.Until<IWebElement>(d => d.FindElement(By.Id("b-7")));
            WebDriverWait wait = new WebDriverWait(driver, TimeSpan.FromSeconds(10));
            IWebElement myDynamicElement = wait.Until<IWebElement>(d => d.FindElement(By.Id("b-7")));
            myDynamicElement.SendKeys("6770065406");
            myDynamicElement = wait.Until<IWebElement>(d => d.FindElement(By.Id("b-8")));
            myDynamicElement.Click();
            IWebElement wynik = wait.Until<IWebElement>(d => d.FindElement(By.Id("caption2_b-3")));
            WebElement dataSprawdzenia = wait.Until<IWebElement>(d => d.FindElement(By.Id("caption2_b-b")));
           */

            int idPakiet = 0;
            string option = "";
            if (args.Length == 0)
            {

                Utils.LogWriter("Brak parametrów wejściowych");
                return;
            }
            try
            {
                if (args.Length == 2)
                {
                    option = args[0].ToUpper();
                    idPakiet = Int32.Parse(args[1]);
                }

                else
                    idPakiet = Int32.Parse(args[0]);
            }
            catch (Exception ex)
            {
                Utils.LogWriter("Błędny parametr wejściowy");
                return;

            }


            if (System.Diagnostics.Process.GetProcessesByName(System.IO.Path.GetFileNameWithoutExtension(System.Reflection.Assembly.GetEntryAssembly().Location)).Count() > 1)
            {
                Utils.LogWriter("Walidator Nip jest już uruchomiony poczekaj na zakończenie jego działania ");
                return;
            }
            //NipNet nipNet = new NipNet(true);// true - właczona komunikacja do konsoli, false - wyłączona
            NipNetLib.ServiceVat.WeryfikacjaVATClient vatClient = new NipNetLib.ServiceVat.WeryfikacjaVATClient();

            using (LexEnaProEntities context = new LexEnaProEntities())
            {
                
                UZD_Pakiet pack = context.UZD_Pakiet.Where(p => p.UZD_PakietId == idPakiet).FirstOrDefault();
                if (pack != null)
                {
                    pack.Opis = "Rozpoczęto walidację NIP: " + DateTime.Now.ToString("yyyy-MM-dd HH:mm");
                    context.SaveChanges();

                }

                // DateTime wYMAGgRANICA = new DateTime(2016, 2, 28);
                DateTime dzis = DateTime.Today;
                 List < UZD_Faktura > faktLst = context.UZD_Faktura.Where(p => p.UZD_PakietId == idPakiet  &&  ( (p.StatusWalidNip == -1 || (  p.StatusWalidNip == 1) || p.StatusWalidNip == 0 || p.StatusWalidNip == null)) ).OrderBy(p=>p.DataWeryfNIP).ToList();
                //List<UZD_Faktura> faktLst = context.UZD_Faktura.Where(p => p.UZD_PakietId == idPakiet && ( p.StatusWalidNip == -1)).OrderBy(p => p.DataWeryfNIP).ToList();

               
                if (faktLst != null && faktLst.Any())
                {
                    List<string> nips = faktLst.Select(p => p.Nip).Distinct().ToList();
                    foreach (string n in nips)
                    {
                        UZD_Faktura uf = faktLst.Where(a => a.Nip == n).FirstOrDefault();
                        if (uf != null)
                        {// pomijamy z dzisiejszą datą 
                            if (uf.DataWeryfNIP.HasValue && uf.StatusWalidNip == 1 && uf.DataWeryfNIP.Value.Date == dzis)
                                continue;

                        }

                        List <UZD_Faktura> faktNip = faktLst.Where(p => p.Nip == n).ToList();
                        foreach (UZD_Faktura f in faktNip) { f.DataWeryfNIP = DateTime.Now; f.StatusNip = "Rozpoczęto walidację"; f.StatusWalidNip = 0; } 
                        Utils.LogWriter("Checking nip " + n);
                        WynikNIP result = null;
                        NipNetLib.ServiceVat.TWynikWeryfikacjiVAT wynik = null;
                        try
                        {
                            wynik = vatClient.SprawdzNIP(n); 
                            //result = nipNet.sprawdzNIP(n, true);
                        }
                        catch (Exception e)
                        {

                            Utils.LogWriter("Błąd podczas pobierania nip dla " +n +" "  +e.Message);
                           
                        }
                        // Utils.LogWriter(result.ToString());
                        Utils.LogWriter(DateTime.Now.ToString() + " " + n + " " + wynik.Komunikat + " " + wynik.Komunikat );
                        // if (result != null)
                        if (wynik != null)
                        {
                            DateTime teraz = DateTime.Now;
                            foreach (UZD_Faktura f in faktNip) { f.DataWeryfNIP =teraz;
                                // f.StatusNip = "Data " +result.Data + " :" + result.Tresc ;
                                f.StatusNip = "Data " + teraz.ToString() + " : [" + wynik.Kod + "]" + wynik.Komunikat;
                                if (f.StatusNip.Length > 512)
                                    f.StatusNip = f.StatusNip.Substring(0, 511);
                                switch (wynik.Kod)
                                {
                                    case NipNetLib.ServiceVat.TKodWeryfikacjiVAT.C:
                                        f.StatusWalidNip = 1;
                                        break;
                                    default:
                                        f.StatusWalidNip = -1;
                                        break;
                                }
                                   //f.StatusWalidNip = result.Status;
                            }


                        }
                        try
                        {
                            context.SaveChanges();
                        }
                        catch (Exception exe)
                        {
                            Utils.LogWriter("Błąd podczas zapisu " + exe.Message + " " + (exe.InnerException != null ? exe.InnerException.Message : ""));

                        }
                    }


                }
                if (pack != null)
                {
                    pack.Opis = "Zakończono walidację NIP: " + DateTime.Now.ToString("yyyy-MM-dd HH:mm");
                    pack.Status = pack.Status + 1;
                    context.SaveChanges();

                }

                {
                   /*     System.Console.WriteLine("Output:" + line);
                        
                        System.Console.WriteLine(result.ToString());
                   */
                    }
                }
            }
            /*
            System.Console.WriteLine(nipNet.sprawdzNIP("8441570989",true));
            //System.Threading.Thread.Sleep(2000);
            System.Console.WriteLine(nipNet.sprawdzNIP("9720865431",true));
            //System.Threading.Thread.Sleep(2000);
            System.Console.WriteLine(nipNet.sprawdzNIP("8992367273",true));
            //System.Threading.Thread.Sleep(2000);
            System.Console.WriteLine(nipNet.sprawdzNIP("5732208760",true));
            System.Console.Write("Done");
            */
        }
    }




